func buildTypeofTests() []sqlTestCase {
	type typeofCase struct {
		expr string
		want string
	}
	cases := []typeofCase{
		{"42", "integer"},
		{"3.14", "real"},
		{"'hello'", "text"},
		{"NULL", "null"},
		{"X'01'", "blob"},
		{"1 + 2", "integer"},
		{"1.0 + 2", "real"},
	}
	tests := make([]sqlTestCase, len(cases))
	for i, c := range cases {
		tests[i] = sqlTestCase{
			name:     fmt.Sprintf("REQ-FUNC-030_typeof/%s", c.expr),
			query:    fmt.Sprintf("SELECT typeof(%s)", c.expr),
			wantRows: [][]interface{}{{c.want}},
		}
	}
	return tests
}

