// ---------------------------------------------------------------------------
// Aggregate functions
// ---------------------------------------------------------------------------

func buildAggregateFuncTests() []sqlTestCase {
	var tests []sqlTestCase
	tests = append(tests, buildCountTests()...)
	tests = append(tests, buildSumAvgTests()...)
	tests = append(tests, buildAggMinMaxTests()...)
	tests = append(tests, buildGroupConcatTests()...)
	tests = append(tests, buildTotalTests()...)
	return tests
}

func buildCountTests() []sqlTestCase {
	setup := []string{
		"CREATE TABLE t_agg(grp TEXT, val INTEGER, nval INTEGER)",
		"INSERT INTO t_agg VALUES('a', 10, NULL)",
		"INSERT INTO t_agg VALUES('a', 20, 1)",
		"INSERT INTO t_agg VALUES('a', 30, NULL)",
		"INSERT INTO t_agg VALUES('b', 40, 2)",
		"INSERT INTO t_agg VALUES('b', 50, 3)",
	}
	return []sqlTestCase{
		{
			name:     "REQ-FUNC-050_count/star",
			setup:    setup,
			query:    "SELECT count(*) FROM t_agg",
			wantRows: [][]interface{}{{int64(5)}},
		},
		{
			name:     "REQ-FUNC-050_count/column",
			setup:    setup,
			query:    "SELECT count(nval) FROM t_agg",
			wantRows: [][]interface{}{{int64(3)}},
		},
		{
			name:     "REQ-FUNC-050_count/empty_table",
			setup:    []string{"CREATE TABLE t_empty(x INTEGER)"},
			query:    "SELECT count(*) FROM t_empty",
			wantRows: [][]interface{}{{int64(0)}},
		},
		{
			name:     "REQ-FUNC-050_count/group_by",
			setup:    setup,
			query:    "SELECT grp, count(*) FROM t_agg GROUP BY grp ORDER BY grp",
			wantRows: [][]interface{}{{"a", int64(3)}, {"b", int64(2)}},
		},
		{
			name:     "REQ-FUNC-050_count/distinct",
			setup:    []string{"CREATE TABLE t_cd(v INTEGER)", "INSERT INTO t_cd VALUES(1),(1),(2),(3),(3)"},
			query:    "SELECT count(DISTINCT v) FROM t_cd",
			wantRows: [][]interface{}{{int64(3)}},
		},
	}
}

