func buildGroupConcatTests() []sqlTestCase {
	setup := []string{
		"CREATE TABLE t_gc(grp TEXT, val TEXT)",
		"INSERT INTO t_gc VALUES('a', 'x')",
		"INSERT INTO t_gc VALUES('a', 'y')",
		"INSERT INTO t_gc VALUES('a', 'z')",
		"INSERT INTO t_gc VALUES('b', 'p')",
		"INSERT INTO t_gc VALUES('b', 'q')",
	}
	return []sqlTestCase{
		{
			name:     "REQ-FUNC-055_group_concat/default_sep",
			setup:    setup,
			query:    "SELECT group_concat(val) FROM t_gc WHERE grp='a'",
			wantRows: [][]interface{}{{"x,y,z"}},
		},
		{
			name:     "REQ-FUNC-055_group_concat/custom_sep",
			setup:    setup,
			query:    "SELECT group_concat(val, '; ') FROM t_gc WHERE grp='a'",
			wantRows: [][]interface{}{{"x; y; z"}},
		},
		{
			name:     "REQ-FUNC-055_group_concat/group_by",
			setup:    setup,
			query:    "SELECT grp, group_concat(val) FROM t_gc GROUP BY grp ORDER BY grp",
			wantRows: [][]interface{}{{"a", "x,y,z"}, {"b", "p,q"}},
		},
		{
			name:     "REQ-FUNC-055_group_concat/empty",
			setup:    []string{"CREATE TABLE t_gce(v TEXT)"},
			query:    "SELECT group_concat(v) FROM t_gce",
			wantRows: [][]interface{}{{nil}},
		},
		{
			name:     "REQ-FUNC-055_group_concat/with_nulls",
			setup:    []string{"CREATE TABLE t_gcn(v TEXT)", "INSERT INTO t_gcn VALUES('a'),(NULL),('c')"},
			query:    "SELECT group_concat(v) FROM t_gcn",
			wantRows: [][]interface{}{{"a,c"}},
		},
		{
			name:     "REQ-FUNC-055_group_concat/integers",
			setup:    []string{"CREATE TABLE t_gci(v INTEGER)", "INSERT INTO t_gci VALUES(1),(2),(3)"},
			query:    "SELECT group_concat(v, '-') FROM t_gci",
			wantRows: [][]interface{}{{"1-2-3"}},
		},
	}
}

